本文所涉及的主要技术有：Vue、Pinia、vue-router

在开发过程中经常需要在页面从详情回到列表时，保留列表页面的滚动位置、筛选条件、分页信息等数据。这个方法网络上已经有很多解决方案，本文仅发表自己的解决办法。
对于列表页面，我们可以使用keep-alive缓存组件，当从详情页面返回时，列表页面会被缓存起来，不会重新渲染。但是这一行为不是可控的，比如我有一个页面A，他是一个导航页，从A-&gt;B，B是一个列表页，从B-&gt;C，C是一个详情页，从C返回B时，B会被缓存起来，不会重新渲染，但是当我从B回到A再进入B时，B页面的状态不会回滚到初始状态，而是被保留在离开的时候，这一情况下我们可能需要操作其他数据来保持正确的渲染。
不同于使用sessionStorage或localStorage来存储数据，这里我采用了Pinia来完成缓存，此方案仅适用于不需要多个浏览器页签同步状态的情况。
// src/store/pageCache.jsimport &#123; defineStore &#125; from &#x27;pinia&#x27;import &#123; shallowRef &#125; from &#x27;vue&#x27;export const usePageCacheStore = defineStore(&#x27;pageCache&#x27;, () =&gt; &#123;  const cacheMap = shallowRef(new Map())  function setCache(key, data) &#123;    cacheMap.value.set(key, data || &#123;&#125;)    cacheMap.value = new Map(cacheMap.value)  &#125;  function getCache(key) &#123;    return cacheMap.value.get(key)  &#125;  function removeCache(key) &#123;    cacheMap.value.delete(key)    cacheMap.value = new Map(cacheMap.value)  &#125;  function clearCache() &#123;    cacheMap.value.clear()    cacheMap.value = new Map()  &#125;  return &#123;    cacheMap,    setCache,    getCache,    removeCache,    clearCache,  &#125;&#125;)

但是pinia仅作为基础功能的封装，要使用还是有一些麻烦，需要自己去清理缓存。
// src/hooks/usePageCache.jsimport &#123; usePageCacheStore &#125; from &#x27;@/stores/pageCache&#x27;/** * 页面缓存Hook * @param &#123;string&#125; cacheKey - 缓存键名 * @param &#123;any&#125; initialData - 初始缓存数据 * @param &#123;string[]&#125; excludeRoutes - 排除的路由数组，这些路由退出时不清除缓存 * @returns &#123;Object&#125; 缓存操作方法 */export function usePageCache(cacheKey, excludeRoutes = []) &#123;  const pageCacheStore = usePageCacheStore()  onMounted(() =&gt; &#123;    pageCacheStore.setCache(cacheKey, &#123;&#125;)  &#125;)  onBeforeRouteLeave((to, from, next) =&gt; &#123;    const shouldExclude = excludeRoutes.some((excludeRoute) =&gt; &#123;      if (typeof excludeRoute !== &#x27;string&#x27;) &#123;        return false      &#125;      if (excludeRoute.includes(&#x27;/&#x27;)) &#123;        return excludeRoute === to.path      &#125; else &#123;        return excludeRoute === to.name      &#125;    &#125;)    if (!shouldExclude) &#123;      pageCacheStore.removeCache(cacheKey)    &#125;    if (import.meta.env.DEV) &#123;      console.log(&#x27;路由退出&#x27;, from.path, &#x27;保留缓存:&#x27;, shouldExclude)    &#125;    next()  &#125;)  function getCache() &#123;    return pageCacheStore.getCache(cacheKey)  &#125;  function setCache(data) &#123;    pageCacheStore.setCache(cacheKey, &#123;      ...pageCacheStore.getCache(cacheKey),      ...data,    &#125;)    if (import.meta.env.DEV) &#123;      console.log(&#x27;设置缓存&#x27;, cacheKey, pageCacheStore.getCache(cacheKey))    &#125;  &#125;  function removeCache() &#123;    pageCacheStore.removeCache(cacheKey)  &#125;  return &#123;    getCache,    setCache,    removeCache,  &#125;&#125;

通过在hooks中使用生命周期钩子函数onMounted和onBeforeRouteLeave，我们可以在组件挂载时初始化缓存，在路由离开时根据规则清除缓存，此时我们只需要关注缓存的注册、更新以及页面返回时的状态恢复即可。

