      body.scroll-lock {
        overflow: hidden;
      }

      .custom-drawer-button {
        background-color: transparent;
        border: none;
        cursor: pointer;
        font-size: 16px;
        color: #28a9ffff;
      }

      .custom-drawer {
        display: none;
        position: fixed;
        top: 0;
        left: 0;
        width: 100%;
        height: 100%;
        background-color: rgba(0, 0, 0, 0.4);
        z-index: 999;
      }

      .custom-drawer.open {
        display: block;
      }

      .drawer-content {
        position: fixed;
        top: 0;
        height: 100%;
        background-color: white;
        z-index: 1000;
        padding: 20px;
        box-shadow: 0 0 10px rgba(0, 0, 0, 0.2);
      }

      .drawer-close {
        position: absolute;
        top: 10px;
        right: 10px;
        background: none;
        border: none;
        font-size: 20px;
        cursor: pointer;
        color: #333;
      }

      .drawer-content {
        animation-duration: 0.3s;
      }

      .drawer-content-inner{
        height: 100%;
        overflow-y: auto;
        margin-top: 20px;
        margin-right: -20px;
        padding-right: 20px;
        white-space: pre-wrap;
        word-break: break-word;
      }



      查看原文



      function openDrawer() {
        const drawer = document.getElementById('custom-drawer');
        const drawerContent = drawer.querySelector('.drawer-content');
        drawer.classList.add('open');
        drawerContent.classList.remove('animate__fadeOutRight');
        drawerContent.classList.add('animate__fadeInRight');
        document.body.classList.add('scroll-lock');
      }

      function closeDrawer() {
        const drawer = document.getElementById('custom-drawer');
        const drawerContent = drawer.querySelector('.drawer-content');
        drawerContent.classList.remove('animate__fadeInRight');
        drawerContent.classList.add('animate__fadeOutRight');
      }

      window.onload = function() {
        const isMobile = /Android|webOS|iPhone|iPad|iPod|BlackBerry|IEMobile|Opera Mini/i.test(navigator.userAgent);
        const drawerWidth = isMobile ? '80%' : '450px';

        const drawer = document.createElement('div');
        drawer.id = 'custom-drawer';
        drawer.classList.add('custom-drawer');

        const drawerContent = document.createElement('div');
        drawerContent.classList.add('drawer-content', 'animate__animated');

        drawerContent.style.width = drawerWidth;
        if ('right' === 'left') {
          drawerContent.style.left = 0
        } else {
          drawerContent.style.right = 0
        }

        drawerContent.addEventListener('animationend', function(event) {
          if (event.animationName.includes('fadeOut')) {
            drawer.classList.remove('open');
            document.body.classList.remove('scroll-lock'); 
          }
        });

        const closeButton = document.createElement('button');
        closeButton.classList.add('drawer-close');
        closeButton.innerHTML = '&times;';
        closeButton.onclick = closeDrawer;

        const contentDiv = document.createElement('div');
        contentDiv.classList.add('drawer-content-inner');
        contentDiv.innerHTML = `那是个不同寻常的夏天。整个城市都像是处在热恋中，人们都不待在家里，条条大街上都是人的河流，在宽阔的地带聚成人的海洋……似乎是那阵阵热风，忽然掀动了人们悠久的梦想……C摇着轮椅在街上走，被人流裹挟着，冲卷着……喧嚣的人声仿佛是那辽阔的阳光和风中固有的音讯。C停下轮椅，坐在河边，心里想：也许梦想都是相似的路途，都是同一种神秘的指使……
什么？在这写作之夜我问他：你说什么？什么神秘的指使？
他埋头想了一会儿，然后我听见他在那河边说：生命本身的密码。很可能，这颗星球上的一切梦想，都是由于生命本身的密码……
他痴迷的眼睛里是涌动的人群，继而是深阔的蓝天。他仰头冥望。我知道，他必是刹那间又看遍了自己的四十年。
我轻声问他：那密码是什么呢？
C久久不语。
我轻声问他：残疾？还是爱情？
我等着，直到我看见，他的目光从深阔的蓝天上降落，涌动的人群重又在他眼睛里升起，他才点点头——声音传进我的写作之夜：是呀，是残疾也是爱情。`;

        drawerContent.appendChild(closeButton);
        drawerContent.appendChild(contentDiv);
        drawer.appendChild(drawerContent);

        document.body.appendChild(drawer);

        window.addEventListener('resize', function() {
          const isMobile = /Android|webOS|iPhone|iPad|iPod|BlackBerry|IEMobile|Opera Mini/i.test(navigator.userAgent);
          const drawerWidth = isMobile ? '80%' : '450px';
          drawerContent.style.width = drawerWidth;
        });

        drawer.addEventListener('click', function(event) {
          if (event.target === drawer) {
            closeDrawer();
          }
        });
      }



